import type { Post, Category, Collection } from '../../types/data.d'

async function getPrisma() {
  if (!process.env.DATABASE_URL) {
    throw new Error('DATABASE_URL not set - dbRepo unavailable')
  }
  // dynamic import so app can run without installing prisma during dev until user opts in
  try {
    // use eval to avoid static analysis by bundlers that would require resolving the package
    // eslint-disable-next-line no-eval
    const pkg = eval("require('@prisma/client')")
    const { PrismaClient } = pkg
    return new PrismaClient()
  } catch (e) {
    throw new Error("@prisma/client is not installed or cannot be loaded")
  }
}

export async function loadAll() {
  const prisma = await getPrisma()
  const posts = await prisma.post.findMany({ include: { tags: { include: { tag: true } }, collections: { include: { collection: true } }, category: true } })
  const cats = await prisma.category.findMany()
  const cols = await prisma.collection.findMany()

  const mappedPosts: Post[] = posts.map((p: any) => ({
    id: p.id,
    thumbnail: p.thumbnail,
    author: p.author,
    caption: p.caption,
    transcript: p.transcript ?? undefined,
    notes: p.notes ?? undefined,
    sourceUrl: p.sourceUrl ?? undefined,
    categoryId: p.categoryId,
    collectionIds: p.collections?.map((pc: any) => pc.collectionId) ?? [],
    tags: p.tags?.map((t: any) => t.tag.name) ?? [],
    savedAt: p.savedAt.toISOString(),
    editedAt: p.editedAt ? p.editedAt.toISOString() : undefined
  }))

  const mappedCats: Category[] = cats.map((c: any) => ({ id: c.id, name: c.name }))
  const mappedCols: Collection[] = cols.map((c: any) => ({ id: c.id, name: c.name, description: c.description }))

  await prisma.$disconnect()
  return { posts: mappedPosts, categories: mappedCats, collections: mappedCols }
}

export async function saveAll(payload: { posts: Post[]; categories: Category[]; collections: Collection[] }) {
  const prisma = await getPrisma()
  // naive sync: upsert categories and collections, replace posts (simple approach)
  for (const c of payload.categories) {
    await prisma.category.upsert({ where: { id: c.id }, update: { name: c.name }, create: { id: c.id, name: c.name } })
  }

  for (const col of payload.collections) {
    await prisma.collection.upsert({ where: { id: col.id }, update: { name: col.name, description: col.description }, create: { id: col.id, name: col.name, description: col.description } })
  }

  // For posts, do simple upsert
  for (const p of payload.posts) {
    const savedAt = new Date(p.savedAt)
    await prisma.post.upsert({
      where: { id: p.id },
      update: {
        thumbnail: p.thumbnail,
        author: p.author,
        caption: p.caption,
        transcript: p.transcript ?? null,
        notes: p.notes ?? null,
        sourceUrl: p.sourceUrl ?? null,
        categoryId: p.categoryId,
        savedAt,
        editedAt: p.editedAt ? new Date(p.editedAt) : null
      },
      create: {
        id: p.id,
        thumbnail: p.thumbnail,
        author: p.author,
        caption: p.caption,
        transcript: p.transcript ?? null,
        notes: p.notes ?? null,
        sourceUrl: p.sourceUrl ?? null,
        categoryId: p.categoryId,
        savedAt,
        editedAt: p.editedAt ? new Date(p.editedAt) : null
      }
    })

    // tags
    if (p.tags && p.tags.length) {
      for (const tName of p.tags) {
        const tagId = `tag-${tName.replace(/\s+/g, '-').toLowerCase()}`
        await prisma.tag.upsert({ where: { id: tagId }, update: { name: tName }, create: { id: tagId, name: tName } })
        await prisma.postTag.upsert({ where: { id: `${p.id}-${tagId}` }, update: {}, create: { id: `${p.id}-${tagId}`, postId: p.id, tagId } })
      }
    }

    // collections
    if (p.collectionIds && p.collectionIds.length) {
      for (const colId of p.collectionIds) {
        await prisma.postCollection.upsert({ where: { id: `${p.id}-${colId}` }, update: {}, create: { id: `${p.id}-${colId}`, postId: p.id, collectionId: colId } })
      }
    }
  }

  await prisma.$disconnect()
}

export const dbRepo = { loadAll, saveAll }

export default dbRepo
